/// <reference types="react-scripts" />

import React from 'react';
import ReactDOM from 'react-dom/client';
import './index.css';
import axios from 'axios';

console.log('✅ App loading with API integration');

const API_URL = 'http://localhost:8000/api';

const App = () => {
  const [text, setText] = React.useState('');
  const [isAnalyzing, setIsAnalyzing] = React.useState(false);
  const [result, setResult] = React.useState<any>(null);
  const [error, setError] = React.useState<string | null>(null);

  const analyzeMessage = async () => {
    if (!text.trim() || text.length < 10) {
      setError('Please enter at least 10 characters');
      return;
    }

    console.log('🔍 Analyzing message:', text);
    setIsAnalyzing(true);
    setError(null);
    setResult(null);

    try {
      const response = await axios.post(`${API_URL}/scam/analyze`, { text });
      console.log('✅ API Response:', response.data);
      setResult(response.data);
    } catch (err: any) {
      console.error('❌ API Error:', err);
      setError(err.response?.data?.detail || 'Failed to analyze. Is the backend running?');
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div style={{ maxWidth: '800px', margin: '40px auto', padding: '20px' }}>
      <h1 style={{ color: '#2563eb' }}>🛡️ AI Scam Hub</h1>
      <h2>Scam Message Analyzer</h2>
      
      <textarea
        style={{ width: '100%', height: '120px', padding: '10px', border: '1px solid #ccc', borderRadius: '5px' }}
        placeholder="Paste a suspicious message here..."
        value={text}
        onChange={(e) => setText(e.target.value)}
      />
      
      <button
        style={{ 
          width: '100%', 
          padding: '12px', 
          backgroundColor: isAnalyzing ? '#999' : '#2563eb',
          color: 'white',
          border: 'none',
          borderRadius: '5px',
          fontSize: '16px',
          cursor: isAnalyzing ? 'not-allowed' : 'pointer',
          marginTop: '10px'
        }}
        onClick={analyzeMessage}
        disabled={isAnalyzing}
      >
        {isAnalyzing ? 'Analyzing...' : 'Analyze Message'}
      </button>

      {error && (
        <div style={{ marginTop: '20px', padding: '15px', backgroundColor: '#fee', border: '1px solid #fcc', borderRadius: '5px', color: '#c00' }}>
          {error}
        </div>
      )}

      {result && (
        <div style={{ marginTop: '20px' }}>
          <h3>Analysis Results</h3>
          
          <div style={{ 
            padding: '15px',
            backgroundColor: result.risk_level === 'High' ? '#fef2f2' : result.risk_level === 'Medium' ? '#fefce8' : '#f0fdf4',
            border: '1px solid',
            borderColor: result.risk_level === 'High' ? '#fca5a5' : result.risk_level === 'Medium' ? '#fde68a' : '#86efac',
            borderRadius: '5px'
          }}>
            <strong>Risk Level: </strong>
            <span style={{ 
              padding: '4px 12px',
              borderRadius: '20px',
              backgroundColor: result.risk_level === 'High' ? '#dc2626' : result.risk_level === 'Medium' ? '#d97706' : '#16a34a',
              color: 'white'
            }}>
              {result.risk_level}
            </span>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px', marginTop: '10px' }}>
            <div style={{ padding: '15px', backgroundColor: '#f3f4f6', borderRadius: '5px' }}>
              <strong>Confidence Score</strong>
              <div style={{ fontSize: '24px', marginTop: '5px' }}>
                {(result.confidence_score * 100).toFixed(0)}%
              </div>
            </div>
            <div style={{ padding: '15px', backgroundColor: '#f3f4f6', borderRadius: '5px' }}>
              <strong>Scam Probability</strong>
              <div style={{ fontSize: '24px', marginTop: '5px' }}>
                {(result.scam_probability * 100).toFixed(0)}%
              </div>
            </div>
          </div>

          {result.explanation && (
            <div style={{ marginTop: '10px', padding: '15px', backgroundColor: '#eff6ff', borderRadius: '5px' }}>
              <strong style={{ color: '#1e40af' }}>Why This Was Detected:</strong>
              <ul style={{ marginTop: '10px', paddingLeft: '20px' }}>
                {result.explanation.map((item: string, i: number) => (
                  <li key={i}>{item}</li>
                ))}
              </ul>
            </div>
          )}

          {result.recommendations && (
            <div style={{ marginTop: '10px', padding: '15px', backgroundColor: '#f0fdf4', borderRadius: '5px' }}>
              <strong style={{ color: '#166534' }}>Recommended Actions:</strong>
              <ul style={{ marginTop: '10px', paddingLeft: '20px' }}>
                {result.recommendations.map((item: string, i: number) => (
                  <li key={i}>✓ {item}</li>
                ))}
              </ul>
            </div>
          )}

          {result.indicators && (
            <div style={{ marginTop: '10px' }}>
              <strong>Detected Indicators:</strong>
              <ul style={{ marginTop: '5px', paddingLeft: '20px' }}>
                {result.indicators.map((indicator: any, i: number) => (
                  <li key={i}>
                    <strong>{indicator.category}:</strong> {indicator.matches.join(', ')}
                    <span style={{ 
                      marginLeft: '10px',
                      padding: '2px 8px',
                      borderRadius: '10px',
                      fontSize: '12px',
                      backgroundColor: indicator.severity === 'High' ? '#fee2e2' : '#fef3c7',
                      color: indicator.severity === 'High' ? '#991b1b' : '#92400e'
                    }}>
                      {indicator.severity}
                    </span>
                  </li>
                ))}
              </ul>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

const rootElement = document.getElementById('root');
if (rootElement) {
  const root = ReactDOM.createRoot(rootElement);
  root.render(<App />);
}
